} else {
  _storage.append(_Word(upTo: lower.bit).complement())
  let filledWords = upper.word &- lower.word
  if filledWords > 0 {
    _storage.append(
      contentsOf: repeatElement(.allBits, count: filledWords &- 1))
  }
  _storage.append(_Word(upTo: upper.bit))
}

